sql:
SELECT analyte, manufacturer
FROM pesticides
WHERE toxicity_class = 'Class II';

external_knowledge:
- '2,4-D' is a commonly used herbicide, often metaphorically referred to as a 'magic potion' for its ability to control harmful weeds; 
- The 'proportions of fertile fields' refer to the percentage of acres treated with '2,4-D';
- The 'dosage given to each acre' is the rate of pesticide application per crop year in pounds per acre;
- The 'success rate' is the efficacy of the pesticide in controlling the target pests.

sql:
SELECT DISTINCT regions.region_name
FROM regions
INNER JOIN treatment_data ON regions.region_id = treatment_data.region_id;

SELECT * FROM treatment_data
WHERE efficacy < 90
ORDER BY one_time_application_rate DESC;

SELECT SUM(rate_per_crop_year) AS total_pesticide_used_2009
FROM treatment_data
WHERE year = '2009';

SELECT pesticides.analyte, pesticides.manufacturer
FROM pesticides
WHERE pesticides.pesticide_id IN (
    SELECT treatment_data.pesticide_id
    FROM treatment_data
);

SELECT AVG(one_time_application_rate) AS average_application_rate
FROM treatment_data
WHERE year = '2009';

SELECT pesticide_id, efficacy
FROM treatment_data
WHERE year = '2009' AND efficacy > 0.90;

SELECT * FROM treatment_data WHERE pesticide_id = (
    SELECT pesticide_id FROM pesticides WHERE analyte = 'Glyphosate'
);
